#include <iostream>

class A
{
public:
    int m_value{};

    A(int value)
        : m_value{ value }
    {
    }
};

class B : virtual public A
{
public:
    int m_bonus{};

    B(int aVal, int bonus)
        : A{ aVal }
        , m_bonus{ bonus }
    {
    }
};

class C : virtual public A
{
public:
    int m_bonus{};

    C(int aVal, int bonus)
        : A{ aVal }
        , m_bonus{ bonus }
    {
    }
};

class D : public B, public C
{
public:
    D(int bVal, int cVal, int dVal)
        : A{ dVal }
        , B{ 0, bVal }
        , C{ 0, cVal }
    {
    }

    void show() const
    {
        std::cout << "A::m_value: " << m_value << '\n';
        std::cout << "B::m_bonus: " << B::m_bonus << '\n';
        std::cout << "C::m_bonus: " << C::m_bonus << '\n';
        std::cout << "total: " << m_value + B::m_bonus + C::m_bonus << '\n';
    }
};

int main()
{
    int bVal{};
    int cVal{};
    int dVal{};
    std::cin >> bVal >> cVal >> dVal;

    D d{ bVal, cVal, dVal };
    d.show();

    return 0;
}
